//! # Spectral Manifest Construction
//!
//! Produces a [`SpectralManifest`] for a layer. Phase 1 ships a STUB
//! extractor (first-k indices, uniform amplitudes) so we can measure
//! file-size shrinkage end-to-end without real calibration. Phase 2
//! swaps in the real attention-pattern probe.
//!
//! Mirrors the data flow of Lean `manifest_from_patterns`, but the
//! Phase 1 version skips the QKV-pattern input and just allocates
//! the first `k` indices uniformly.

use super::format::SpectralManifest;

/// STUB: produce a manifest selecting the first `k = ⌈coverage × d⌉`
/// indices, with uniform amplitude and phase. Useful for end-to-end
/// file-size measurement before calibration is wired in.
///
/// `coverage` is clamped to `[0.0, 1.0]`. Empirical sweet spot per the
/// Lean `cascade_at_thirty_percent` witness is `0.30`.
pub fn stub_first_k_manifest(d: u32, coverage: f32) -> SpectralManifest {
    let coverage = coverage.clamp(0.0, 1.0);
    // Integer-math derivation to avoid the `100.0_f32 * 0.30_f32 → 30.000001`
    // float-precision trap that previously gave k=31 for d=100, coverage=0.30.
    let k = ((d as u64 * (coverage * 1_000.0).round() as u64 + 500) / 1_000) as u32;
    let k = k.min(d);
    SpectralManifest {
        d,
        k,
        standing_indices: (0..k).collect(),
        amplitudes: vec![0.5; k as usize],
        phase_alignment: vec![0.7; k as usize],
    }
}

/// STUB: produce a manifest selecting indices on a uniform stride. More
/// representative of "real" calibration patterns (a real manifest will
/// have indices scattered across the dimension space, not clustered at
/// the start) so the file-size measurement isn't biased by tensor
/// locality artifacts.
pub fn stub_strided_manifest(d: u32, coverage: f32) -> SpectralManifest {
    let coverage = coverage.clamp(0.0, 1.0);
    let k = ((d as f32) * coverage).ceil() as u32;
    let k = k.min(d);
    let stride = if k == 0 { 1 } else { d / k };
    let stride = stride.max(1);
    let indices: Vec<u32> = (0..k).map(|i| (i * stride).min(d - 1)).collect();
    SpectralManifest {
        d,
        k,
        standing_indices: indices,
        amplitudes: vec![0.5; k as usize],
        phase_alignment: vec![0.7; k as usize],
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn first_k_manifest_at_thirty_percent_is_well_formed() {
        let m = stub_first_k_manifest(8192, 0.30);
        assert!(m.is_well_formed());
        assert!(m.k as f32 / m.d as f32 >= 0.299);
        assert!(m.k as f32 / m.d as f32 <= 0.301);
    }

    #[test]
    fn strided_manifest_indices_within_bounds() {
        let m = stub_strided_manifest(8192, 0.30);
        assert!(m.is_well_formed());
        for &i in &m.standing_indices {
            assert!(i < m.d, "index {} out of bounds for d={}", i, m.d);
        }
    }

    #[test]
    fn coverage_clamps_above_one() {
        let m = stub_first_k_manifest(100, 1.5);
        assert_eq!(m.k, 100);
        assert!(m.is_well_formed());
    }

    #[test]
    fn coverage_clamps_below_zero() {
        let m = stub_first_k_manifest(100, -0.5);
        assert_eq!(m.k, 0);
        assert!(m.is_well_formed());
    }
}
